import{_ as t,o as e,c as l,a2 as i}from"./chunks/framework.B8zgMDLd.js";const c=JSON.parse('{"title":"Install Tolaria","description":"","frontmatter":{},"headers":[],"relativePath":"start/install.md","filePath":"start/install.md"}'),s={name:"start/install.md"};function r(o,a,n,d,h,p){return e(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="install-tolaria" tabindex="-1">Install Tolaria <a class="header-anchor" href="#install-tolaria" aria-label="Permalink to &quot;Install Tolaria&quot;">​</a></h1><p>Tolaria publishes desktop builds for macOS, Windows, and Linux. macOS is the primary day-to-day development target, with Windows and Linux builds supported through the release pipeline and fixed as platform issues are found.</p><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h2><p>Use the latest stable release unless you are intentionally testing pre-release builds:</p><ul><li><a href="https://tolaria.md/download/" target="_self">Download the latest stable build</a></li><li><a href="https://github.com/refactoringhq/tolaria/releases" target="_blank" rel="noreferrer">Browse all GitHub releases</a></li><li><a href="/tolaria/releases/">Read the release notes</a></li></ul><h2 id="homebrew" tabindex="-1">Homebrew <a class="header-anchor" href="#homebrew" aria-label="Permalink to &quot;Homebrew&quot;">​</a></h2><p>On macOS you can install the cask:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tolaria</span></span></code></pre></div><h2 id="platform-status" tabindex="-1">Platform Status <a class="header-anchor" href="#platform-status" aria-label="Permalink to &quot;Platform Status&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td>macOS</td><td>Primary</td><td>Apple Silicon and Intel builds are published. Homebrew is available.</td></tr><tr><td>Windows</td><td>Supported, early</td><td>NSIS installers and signed updater bundles are published. Some shell and menu behavior can still need Windows-specific fixes.</td></tr><tr><td>Linux</td><td>Supported, early</td><td>AppImage and deb artifacts are published. Desktop behavior depends on distribution WebKitGTK and input-method integration.</td></tr></tbody></table><p>See <a href="/tolaria/reference/supported-platforms">Supported Platforms</a> for the current support policy.</p><h2 id="after-installing" tabindex="-1">After Installing <a class="header-anchor" href="#after-installing" aria-label="Permalink to &quot;After Installing&quot;">​</a></h2><ol><li>Open Tolaria.</li><li>Choose the Getting Started vault if you want a guided sample.</li><li>Or open an existing folder of Markdown files as a vault.</li><li>Use the command palette with <code>Cmd+K</code> on macOS or <code>Ctrl+K</code> on Linux and Windows.</li></ol>',13)])])}const b=t(s,[["render",r]]);export{c as __pageData,b as default};
